// src/pages/Annotate.js
import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';

import AnnotationTopBar from '../components/AnnotationTopBar';
import AnnotationCanvas from '../components/AnnotationCanvas';
import AnnotationListSidebar from '../components/AnnotationListSidebar';
import './Annotate.css';

export default function Annotate() {
  const navigate = useNavigate();
  const { state } = useLocation();
  const folderInfo = state?.folderInfo;
  const mode = state?.mode || 'regular'; // 'regular' or 'segmentation'

  if (!folderInfo) {
    return (
      <div style={{ padding: 20 }}>
        <h2>No folder info found. Please create a task first.</h2>
        <button onClick={() => navigate('/')}>Go Home</button>
      </div>
    );
  }

  const { folderId, taskName, labelClasses, files } = folderInfo;

  // Annotations state
  const [annotations, setAnnotations] = useState({});
  const [undoStack, setUndoStack] = useState([]);
  const [redoStack, setRedoStack] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);

  // Tool selection
  const [selectedTool, setSelectedTool] = useState('move');

  // Segmentation state (only used in segmentation mode)
  const [segmentationType, setSegmentationType] = useState('instance');
  const [panopticOption, setPanopticOption] = useState('instance');

  const [selectedLabelClass, setSelectedLabelClass] = useState(
    labelClasses[0]?.name || ''
  );
  const [scale, setScale] = useState(1.0);

  // Modal state for adding new labels
  const [showAddLabelModal, setShowAddLabelModal] = useState(false);
  const [newLabelName, setNewLabelName] = useState('');
  const [newLabelColor, setNewLabelColor] = useState('#ff0000');

  const currentFileUrl = files[currentIndex]?.url;
  const currentShapes = annotations[currentFileUrl] || [];

  const handleAnnotationsChange = (newShapes) => {
    const updated = {
      ...annotations,
      [currentFileUrl]: newShapes,
    };
    setUndoStack([...undoStack, annotations]);
    setRedoStack([]);
    setAnnotations(updated);
  };

  // Undo/Redo
  const undo = () => {
    if (undoStack.length === 0) return;
    const prev = undoStack[undoStack.length - 1];
    setRedoStack([...redoStack, annotations]);
    setUndoStack(undoStack.slice(0, -1));
    setAnnotations(prev);
  };

  const redo = () => {
    if (redoStack.length === 0) return;
    const next = redoStack[redoStack.length - 1];
    setUndoStack([...undoStack, annotations]);
    setRedoStack(redoStack.slice(0, -1));
    setAnnotations(next);
  };

  // Deletion/Update
  const handleDeleteAnnotation = (index) => {
    const arr = [...currentShapes];
    arr.splice(index, 1);
    handleAnnotationsChange(arr);
  };

  const handleUpdateAnnotation = (index, changes) => {
    const arr = [...currentShapes];
    arr[index] = { ...arr[index], ...changes };
    handleAnnotationsChange(arr);
  };

  // Navigation
  const handlePrev = () => {
    if (currentIndex > 0) setCurrentIndex((i) => i - 1);
  };
  const handleNext = () => {
    if (currentIndex < files.length - 1) setCurrentIndex((i) => i + 1);
  };

  // Zoom
  const handleZoomIn = () => setScale((s) => Math.min(s + 0.1, 5));
  const handleZoomOut = () => setScale((s) => Math.max(s - 0.1, 0.2));
  const handleWheelZoom = (deltaY) => {
    if (deltaY < 0) handleZoomIn();
    else handleZoomOut();
  };

  // Save
  const handleSave = async () => {
    const bodyData = {
      folderId,
      taskName,
      labelClasses,
      annotations,
    };
    try {
      const res = await fetch('http://localhost:4000/api/annotations', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(bodyData),
      });
      const data = await res.json();
      alert('Saved: ' + data.message);
    } catch (err) {
      console.error(err);
      alert('Error saving');
    }
  };

  const handleFillBackground = () => {
    if (!currentFileUrl) return;
    const img = new window.Image();
    img.src = currentFileUrl;
    img.onload = () => {
      const width = img.width;
      const height = img.height;
      const bgAnn = computeBackgroundPolygon(width, height, currentShapes, labelClasses);
      const newShapes = currentShapes.filter(ann => ann.label.toLowerCase() !== 'background');
      newShapes.push(bgAnn);
      handleAnnotationsChange(newShapes);
    };
  };

  function computeBackgroundPolygon(imageWidth, imageHeight, shapes, labelClasses) {
    const outer = [
      { x: 0, y: 0 },
      { x: imageWidth, y: 0 },
      { x: imageWidth, y: imageHeight },
      { x: 0, y: imageHeight },
    ];
    const holes = [];
    shapes.forEach(ann => {
      if (ann.type === 'bbox') {
        const hole = [
          { x: ann.x, y: ann.y },
          { x: ann.x + ann.width, y: ann.y },
          { x: ann.x + ann.width, y: ann.y + ann.height },
          { x: ann.x, y: ann.y + ann.height },
        ];
        holes.push(hole);
      } else if (ann.type === 'polygon') {
        if (ann.label.toLowerCase() !== 'background') {
          holes.push(ann.points);
        }
      } else if (ann.type === 'ellipse') {
        const hole = [];
        const numPoints = 20;
        for (let i = 0; i < numPoints; i++) {
          const angle = (2 * Math.PI * i) / numPoints;
          const x = ann.x + ann.radiusX * Math.cos(angle);
          const y = ann.y + ann.radiusY * Math.sin(angle);
          hole.push({ x, y });
        }
        holes.push(hole);
      }
    });
    let bgColor = '#000000';
    if (
      labelClasses &&
      labelClasses.some(
        (lc) =>
          lc.color.toLowerCase() === '#000000' &&
          lc.name.toLowerCase() !== 'background'
      )
    ) {
      bgColor = '#010101';
    }
    return {
      type: 'polygon',
      points: outer,
      holes: holes,
      label: 'background',
      color: bgColor,
    };
  }

  const handleFinishShape = () => {
    setSelectedTool('move');
  };

  // Keyboard shortcuts
  useEffect(() => {
    const handleKey = (e) => {
      const key = e.key;
      if (key === 'm' || key === 'M') {
        setSelectedTool('move');
      } else if (key === 'b' || key === 'B') {
        setSelectedTool('bbox');
      } else if (key === 'p' || key === 'P') {
        setSelectedTool('polygon');
      } else if (key === 'l' || key === 'L') {
        setSelectedTool('polyline');
      } else if (key === 'o' || key === 'O') {
        setSelectedTool('point');
      } else if (key === 'e' || key === 'E') {
        setSelectedTool('ellipse');
      } else if ((key === 's' || key === 'S') && e.ctrlKey) {
        e.preventDefault();
        handleSave();
      } else if (key === 's' || key === 'S') {
        if (mode === 'segmentation') {
          setSelectedTool('segmentation');
        }
      }
      if (key === 'Escape') {
        const event = new CustomEvent('cancel-annotation');
        window.dispatchEvent(event);
      }
      if (key === 'ArrowRight') {
        handleNext();
      } else if (key === 'ArrowLeft') {
        handlePrev();
      }
      if (e.ctrlKey && (key === 'z' || key === 'Z')) {
        e.preventDefault();
        undo();
      } else if (e.ctrlKey && (key === 'y' || key === 'Y')) {
        e.preventDefault();
        redo();
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [annotations, undoStack, redoStack, mode]);

  return (
    <div className="annotate-container">
      <AnnotationTopBar
        onHome={() => navigate('/')}
        onPrev={handlePrev}
        onNext={handleNext}
        onSave={handleSave}
        onZoomIn={handleZoomIn}
        onZoomOut={handleZoomOut}
        onExport={() => { }}
        currentIndex={currentIndex}
        total={files.length}
        taskName={taskName}
      />

      <div className="toolbar">
        <button onClick={undo}>Undo (Ctrl+Z)</button>
        <button onClick={redo}>Redo (Ctrl+Y)</button>
        <button onClick={handleFillBackground}>Fill Background</button>
      </div>

      <div className="annotate-main">
        <div className="tools-sidebar">
          <h3>Tools</h3>
          <label>
            <input
              type="radio"
              name="tool"
              value="move"
              checked={selectedTool === 'move'}
              onChange={() => setSelectedTool('move')}
            />
            Move (M)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="bbox"
              checked={selectedTool === 'bbox'}
              onChange={() => setSelectedTool('bbox')}
            />
            BBox (B)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="polygon"
              checked={selectedTool === 'polygon'}
              onChange={() => setSelectedTool('polygon')}
            />
            Polygon (P)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="polyline"
              checked={selectedTool === 'polyline'}
              onChange={() => setSelectedTool('polyline')}
            />
            Polyline (L)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="point"
              checked={selectedTool === 'point'}
              onChange={() => setSelectedTool('point')}
            />
            Point (O)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="ellipse"
              checked={selectedTool === 'ellipse'}
              onChange={() => setSelectedTool('ellipse')}
            />
            Ellipse (E)
          </label>
          {mode === 'segmentation' && (
            <>
              <label>
                <input
                  type="radio"
                  name="tool"
                  value="segmentation"
                  checked={selectedTool === 'segmentation'}
                  onChange={() => setSelectedTool('segmentation')}
                />
                Segmentation (S)
              </label>
              <div className="segmentation-options">
                <label>Type:</label>
                <select value={segmentationType} onChange={(e) => setSegmentationType(e.target.value)}>
                  <option value="instance">Instance</option>
                  <option value="semantic">Semantic</option>
                  <option value="panoptic">Panoptic</option>
                </select>
                {segmentationType === 'panoptic' && (
                  <div>
                    <label>
                      <input
                        type="radio"
                        name="panopticOption"
                        value="instance"
                        checked={panopticOption === 'instance'}
                        onChange={() => setPanopticOption('instance')}
                      />
                      Instance
                    </label>
                    <label>
                      <input
                        type="radio"
                        name="panopticOption"
                        value="semantic"
                        checked={panopticOption === 'semantic'}
                        onChange={() => setPanopticOption('semantic')}
                      />
                      Semantic
                    </label>
                  </div>
                )}
              </div>
            </>
          )}
          <h3>Active Label</h3>
          <div className="active-label-section">
            <select value={selectedLabelClass} onChange={(e) => setSelectedLabelClass(e.target.value)}>
              {labelClasses.map((lc, i) => (
                <option key={i} value={lc.name}>
                  {lc.name}
                </option>
              ))}
            </select>
            <button onClick={() => setShowAddLabelModal(true)}>Add Labels</button>
          </div>
          <div className="note-area">
            <p><strong>Shortcuts:</strong></p>
            <ul>
              <li>M/B/P/L/O/E => Tools</li>
              {mode === 'segmentation' && <li>S => Segmentation</li>}
              <li>Ctrl+S => Save</li>
              <li>Esc => Cancel shape</li>
              <li>ArrowLeft => Prev image</li>
              <li>ArrowRight => Next image</li>
              <li>Ctrl+Z => Undo</li>
              <li>Ctrl+Y => Redo</li>
              <li>Ctrl+C => Copy selected</li>
              <li>Ctrl+V => Paste annotation</li>
            </ul>
          </div>
        </div>

        <div className="canvas-area">
          {currentFileUrl ? (
            <AnnotationCanvas
              fileUrl={currentFileUrl}
              annotations={currentShapes}
              onAnnotationsChange={handleAnnotationsChange}
              selectedTool={selectedTool}
              scale={scale}
              onWheelZoom={handleWheelZoom}
              activeLabelColor={
                labelClasses.find((l) => l.name === selectedLabelClass)?.color || '#ff0000'
              }
              onFinishShape={handleFinishShape}
              onDeleteAnnotation={handleDeleteAnnotation}
              activeLabel={selectedLabelClass}
              labelClasses={labelClasses}
              segmentationType={mode === 'segmentation' ? segmentationType : undefined}
              panopticOption={mode === 'segmentation' ? panopticOption : undefined}
              enableSegmentation={mode === 'segmentation'}
            />
          ) : (
            <div style={{ textAlign: 'center', margin: 'auto' }}>
              No images found
            </div>
          )}
        </div>

        <AnnotationListSidebar
          annotations={currentShapes}
          onDeleteAnnotation={handleDeleteAnnotation}
          onUpdateAnnotation={handleUpdateAnnotation}
          labelClasses={labelClasses}
        />
      </div>

      {showAddLabelModal && (
        <div className="modal-backdrop">
          <div className="modal">
            <h2>Add New Label</h2>
            <input
              type="text"
              placeholder="Label Name"
              value={newLabelName}
              onChange={(e) => setNewLabelName(e.target.value)}
            />
            <input
              type="color"
              value={newLabelColor}
              onChange={(e) => setNewLabelColor(e.target.value)}
            />
            <div className="modal-actions">
              <button
                onClick={() => {
                  if (!newLabelName.trim()) {
                    alert('Label name cannot be empty');
                    return;
                  }
                  const newLabel = { name: newLabelName.trim(), color: newLabelColor };
                  // Here you might update your labelClasses state (e.g. via a context or lifting state up).
                  // For this demo we simply alert and close the modal.
                  alert('New label added (please refresh to see changes).');
                  setShowAddLabelModal(false);
                }}
              >
                Add
              </button>
              <button onClick={() => setShowAddLabelModal(false)}>Cancel</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
